  1	import { type FC, useCallback, useState } from 'react';
  2	import { FormGroupWithHelpText } from 'src/components/common/FormGroupWithHelpText/FormGroupWithHelpText';
  3	
  4	import ModalForm from '@components/ModalForm/ModalForm';
  5	import {
  6	  NetworkMapModelGroupVersionKind,
  7	  StorageMapModelGroupVersionKind,
  8	  type V1beta1NetworkMap,
  9	  type V1beta1Plan,
 10	  type V1beta1StorageMap,
 11	} from '@kubev2v/types';
 12	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 13	import { Stack, StackItem, TextInput } from '@patternfly/react-core';
 14	import { getName } from '@utils/crds/common/selectors';
 15	import {
 16	  getPlanNetworkMapName,
 17	  getPlanNetworkMapNamespace,
 18	  getPlanStorageMapName,
 19	  getPlanStorageMapNamespace,
 20	} from '@utils/crds/plans/selectors';
 21	import { ForkliftTrans, useForkliftTranslation } from '@utils/i18n';
 22	
 23	import { createDuplicatePlanAndMapResources } from './utils/utils';
 24	
 25	type DuplicateModalProps = {
 26	  plan: V1beta1Plan;
 27	};
 28	
 29	const DuplicateModal: FC<DuplicateModalProps> = ({ plan }) => {
 30	  const { t } = useForkliftTranslation();
 31	  const name = getName(plan);
 32	  const [newName, setNewName] = useState<string>(`copy-of-${name}`);
 33	
 34	  const [networkMap] = useK8sWatchResource<V1beta1NetworkMap>({
 35	    groupVersionKind: NetworkMapModelGroupVersionKind,
 36	    isList: false,
 37	    name: getPlanNetworkMapName(plan),
 38	    namespace: getPlanNetworkMapNamespace(plan),
 39	    namespaced: true,
 40	  });
 41	
 42	  const [storageMap] = useK8sWatchResource<V1beta1StorageMap>({
 43	    groupVersionKind: StorageMapModelGroupVersionKind,
 44	    isList: false,
 45	    name: getPlanStorageMapName(plan),
 46	    namespace: getPlanStorageMapNamespace(plan),
 47	    namespaced: true,
 48	  });
 49	
 50	  const onChange = (value: string): void => {
 51	    setNewName(value);
 52	  };
 53	
 54	  const onDuplicate = useCallback(
 55	    async () =>
 56	      createDuplicatePlanAndMapResources({ networkMap, newPlanName: newName, plan, storageMap }),
 57	    [newName, networkMap, storageMap, plan],
 58	  );
 59	
 60	  return (
 61	    <ModalForm
 62	      confirmLabel={t('Duplicate')}
 63	      title={t('Duplicate migration plan')}
 64	      onConfirm={onDuplicate}
 65	    >
 66	      <ForkliftTrans>
 67	        <Stack hasGutter>
 68	          <StackItem>
 69	            Duplicate plan <strong className="co-break-word">{name}</strong>?
 70	          </StackItem>
 71	          <FormGroupWithHelpText
 72	            label={t('New migration plan name')}
 73	            fieldId="name"
 74	            helperText={t('Kubernetes name of the new migration Plan resource')}
 75	          >
 76	            <TextInput
 77	              spellCheck="false"
 78	              value={newName}
 79	              id="name"
 80	              onChange={(_, value) => {
 81	                onChange(value);
 82	              }}
 83	            />
 84	          </FormGroupWithHelpText>
 85	          <StackItem>
 86	            All needed Mappings and Hooks will be duplicated and attached to the new Plan.
 87	          </StackItem>
 88	          <StackItem>
 89	            Storage map: <strong className="co-break-word">{storageMap?.metadata?.name}</strong>
 90	          </StackItem>
 91	          <StackItem>
 92	            Network map: <strong className="co-break-word">{networkMap?.metadata?.name}</strong>
 93	          </StackItem>
 94	        </Stack>
 95	      </ForkliftTrans>
 96	    </ModalForm>
 97	  );
 98	};
 99	
100	export default DuplicateModal;

